import{promises as m}from"node:fs";import{join as a}from"node:path";import{readJson as f,writeJson as h}from"./fs-utils.js";import{chaptersDir as i,chapterFileName as p}from"./paths.js";export async function loadChapter(r,n,t){const e=a(i(r,n),p(t));return f(e)}export async function saveChapter(r,n,t){const e=a(i(r,n),p(t.number));await h(e,t)}export async function listChapters(r,n){const t=i(r,n);try{const e=await m.readdir(t),c=[];for(const o of e){if(!o.endsWith(".json"))continue;const s=await f(a(t,o));if(s){const{body:l,...u}=s;c.push(u)}}return c.sort((o,s)=>o.number-s.number)}catch{return[]}}export async function nextChapterNumber(r,n){const t=await listChapters(r,n);return t.length===0?1:t[t.length-1].number+1}
